                    <h2 id="listings-PUTapi-posts--id-">Update listing</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Note: The fields 'pictures', 'package_id' and 'payment_method_id' are only available with the single step listing edition.
The field 'admin_code' is only available when the listing's country's 'admin_type' column is set to 1 or 2.</p>

<span id="example-requests-PUTapi-posts--id-">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request PUT \
    "https://jobclass.laraclassifier.local/api/posts/14" \
    --header "Authorization: Bearer {YOUR_AUTH_TOKEN}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --header "Content-Language: en" \
    --header "X-AppApiToken: a25ydDlKdDRwT2wzYjAxV1hvc0hSUmQxYklTTE1pRHU=" \
    --header "X-AppType: docs" \
    --data "{
    \"category_id\": 1,
    \"post_type_id\": 1,
    \"title\": \"John Doe\",
    \"description\": \"Beatae placeat atque tempore consequatur animi magni omnis.\",
    \"salary_type_id\": \"totam\",
    \"contact_name\": \"John Doe\",
    \"auth_field\": \"email\",
    \"phone\": \"+17656766467\",
    \"phone_country\": null,
    \"city_id\": 13,
    \"accept_terms\": false,
    \"email\": \"john.doe@domain.tld\",
    \"country_code\": \"US\",
    \"company_id\": 20,
    \"admin_code\": \"0\",
    \"price\": 5000,
    \"negotiable\": false,
    \"phone_hidden\": false,
    \"latest_update_ip\": \"127.0.0.1\",
    \"accept_marketing_offers\": false,
    \"is_permanent\": false,
    \"tags\": \"car,automotive,tesla,cyber,truck\",
    \"package_id\": 2,
    \"payment_method_id\": 5
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "https://jobclass.laraclassifier.local/api/posts/14"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_TOKEN}",
    "Content-Type": "application/json",
    "Accept": "application/json",
    "Content-Language": "en",
    "X-AppApiToken": "a25ydDlKdDRwT2wzYjAxV1hvc0hSUmQxYklTTE1pRHU=",
    "X-AppType": "docs",
};

let body = {
    "category_id": 1,
    "post_type_id": 1,
    "title": "John Doe",
    "description": "Beatae placeat atque tempore consequatur animi magni omnis.",
    "salary_type_id": "totam",
    "contact_name": "John Doe",
    "auth_field": "email",
    "phone": "+17656766467",
    "phone_country": null,
    "city_id": 13,
    "accept_terms": false,
